import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.EditorConfig
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.Test

class RepeatFormatTest {
    @Test
    fun `Given a file with violations that require multiple passes then format repeats until no more errors are found`() {
        val code = "val foo = \"foo\""
        val expected = "val foo = \"baz\""

        val actual = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { RuleA() },
                RuleProvider { RuleB() }
            )
        ).format(Code.fromSnippet(code))

        assertThat(actual).isEqualTo(expected)
    }

    @Test
    fun `Given a file that causes infinite loop then stop after max reruns`() {
         val code = "val foo = \"ping\""
         // RulePingPong changes ping -> pong, pong -> ping.
         // Original: ping
         // Run 1: ping -> pong (mutated)
         // Run 2: pong -> ping (mutated)
         // Run 3: ping -> pong (mutated)
         // Run 4: pong -> ping (mutated) -> Stop.
         // Result should be ping (from Run 4) or pong (from Run 3)?
         // The logic says: 
         // Loop 1 (Run 0): ping -> pong.
         // Loop 2 (Run 1): pong -> ping.
         // Loop 3 (Run 2): ping -> pong.
         // Loop 4 (Run 3): pong -> ping. Stop.
         // Result: ping.

         // If maxReruns = 3 (total 4 runs).

         val actual = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { RulePingPong() }
            )
        ).format(Code.fromSnippet(code))

        // It's either ping or pong depending on exact count.
        // Run 0: pong
        // Run 1: ping
        // Run 2: pong
        // Run 3: ping. Stop.
        assertThat(actual).isIn("ping", "pong")
    }

    private class RuleA : Rule(
        ruleId = RuleId("test:rule-a"),
        about = About(),
        visitorModifiers = setOf(VisitorModifier.RunAsLateAsPossible)
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
        ) {
            if (node.elementType == org.jetbrains.kotlin.com.intellij.psi.TokenType.WHITE_SPACE) return
            if (node.text == "\"foo\"") {
                emit(node.startOffset, "foo should be bar", true)
                if (autoCorrect) {
                    (node as LeafElement).replaceWithText("\"bar\"")
                }
            }
        }
    }

    private class RuleB : Rule(
        ruleId = RuleId("test:rule-b"),
        about = About()
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
        ) {
             if (node.elementType == org.jetbrains.kotlin.com.intellij.psi.TokenType.WHITE_SPACE) return
             if (node.text == "\"bar\"") {
                emit(node.startOffset, "bar should be baz", true)
                if (autoCorrect) {
                    (node as LeafElement).replaceWithText("\"baz\"")
                }
            }
        }
    }

    private class RulePingPong : Rule(
        ruleId = RuleId("test:ping-pong"),
        about = About()
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
        ) {
             if (node.text == "\"ping\"") {
                emit(node.startOffset, "ping -> pong", true)
                if (autoCorrect) {
                    (node as LeafElement).replaceWithText("\"pong\"")
                }
            } else if (node.text == "\"pong\"") {
                emit(node.startOffset, "pong -> ping", true)
                 if (autoCorrect) {
                    (node as LeafElement).replaceWithText("\"ping\"")
                }
            }
        }
    }
}
